/*==============================================================*/
/* Table: CATCOP                                                */
/*==============================================================*/
CREATE TABLE CATCOP
(
    ID_CATCOP_CODE    VARCHAR(4)  NOT NULL,
    CATCOP_NAME       VARCHAR(32) NOT NULL,
    CATCOP_COLOR_CODE VARCHAR(8)  NOT NULL,
    CATCOP_VALID_FROM TIMESTAMP,
    CATCOP_VALID_TO   TIMESTAMP   NULL,
    CATCOP_CREATED_BY VARCHAR(16),
    CATCOP_UPDATED_BY VARCHAR(16),
    CATCOP_CREATED_AT TIMESTAMP,
    CATCOP_UPDATED_AT TIMESTAMP,
    PRIMARY KEY (ID_CATCOP_CODE)
);

ALTER TABLE CATCOP
    COMMENT 'COLORES A';

/*==============================================================*/
/* Index: CAICOP_NAME                                           */
/*==============================================================*/
CREATE UNIQUE INDEX CAICOP_NAME ON CATCOP (CATCOP_NAME);


/*==============================================================*/
/* Table: CATCOL                                                */
/*==============================================================*/
CREATE TABLE CATCOL
(
    ID_CATCOL_CODE       VARCHAR(4) NOT NULL,
    XID_CATCOP_CODE      VARCHAR(4),
    CATCOL_INDEX         INT        NOT NULL,
    CATCOL_DOSAGE        DECIMAL(8,4) NOT NULL,
    CATCOL_DESCRIPTION   VARCHAR(64) NOT NULL,
    CATCOL_COLOR_CODE    VARCHAR(8)  NOT NULL,
    CATCOL_OBSERVATION   VARCHAR(255),
    CATCOL_VALID_FROM    TIMESTAMP,
    CATCOL_VALID_TO      TIMESTAMP NULL,
    CATCOL_CREATED_BY    VARCHAR(16),
    CATCOL_UPDATED_BY    VARCHAR(16),
    CATCOL_CREATED_AT    TIMESTAMP,
    CATCOL_UPDATED_AT    TIMESTAMP,
    PRIMARY KEY (ID_CATCOL_CODE)
);

ALTER TABLE CATCOL COMMENT 'COLORES B';

ALTER TABLE CATCOL ADD CONSTRAINT XID_CATCOL_CODE_XID_CATCOP_CODE FOREIGN KEY (XID_CATCOP_CODE)
    REFERENCES CATCOP (ID_CATCOP_CODE) ON DELETE RESTRICT;


/*==============================================================*/
/* Table: CATCATCOL                                             */
/*==============================================================*/
CREATE TABLE CATCATCOL
(
    ID_CATCATCOL_CODE    INT NOT NULL AUTO_INCREMENT,
    CATCATCOL_NAME       VARCHAR(256) NOT NULL,
    CATCATCOL_COLOR_CODE VARCHAR(8)  NOT NULL,
    CATCATCOL_VALID_FROM TIMESTAMP,
    CATCATCOL_VALID_TO   TIMESTAMP NULL,
    CATCATCOL_CREATED_BY VARCHAR(16),
    CATCATCOL_UPDATED_BY VARCHAR(16),
    CATCATCOL_CREATED_AT TIMESTAMP,
    CATCATCOL_UPDATED_AT TIMESTAMP,
    PRIMARY KEY (ID_CATCATCOL_CODE)
);

ALTER TABLE CATCATCOL COMMENT 'CATALOGO COLOR';






